  function svgIcon(name, size, color) {
    return `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="${color||'currentColor'}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">${ICONS[name]}</svg>`;
  }
  window.svgIcon = svgIcon;

  // Trail bounds for fitBounds
  const lats = window.TRAIL.map(p => p[0]);
  const lngs = window.TRAIL.map(p => p[1]);
  window.TRAIL_BOUNDS = [[Math.min(...lngs), Math.min(...lats)], [Math.max(...lngs), Math.max(...lats)]];

  // Render the elevation sparkline inside the given <svg> element using the full trail
  function drawElevSparkline(svg, progressFrac) {
    const W = 300, H = 60, PAD = 4;
    const T = window.TRAIL;
    const eles = T.map(p => p[2]);
    const minE = Math.min(...eles), maxE = Math.max(...eles);
    function hav(a, b, c, d) {
      const R = 6371000;
      const dLat = (c - a) * Math.PI / 180, dLng = (d - b) * Math.PI / 180;
      const A = Math.sin(dLat / 2) ** 2 + Math.cos(a * Math.PI / 180) * Math.cos(c * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
      return R * 2 * Math.atan2(Math.sqrt(A), Math.sqrt(1 - A));
    }
    const cum = [0];
    for (let i = 1; i < T.length; i++) cum.push(cum[i - 1] + hav(T[i - 1][0], T[i - 1][1], T[i][0], T[i][1]));
    const total = cum[cum.length - 1];
    const x = f => PAD + f * (W - 2 * PAD);
    const y = e => H - PAD - ((e - minE) / (maxE - minE)) * (H - 2 * PAD);

    const full = T.map((p, i) => `${i === 0 ? 'M' : 'L'}${x(cum[i] / total).toFixed(1)},${y(p[2]).toFixed(1)}`).join(' ');
    const fullArea = full + ` L${x(1).toFixed(1)},${H - PAD} L${PAD},${H - PAD} Z`;

    const targetD = progressFrac * total;
    let pi = 0;
    for (let i = 0; i < cum.length - 1; i++) if (cum[i] <= targetD) pi = i;
    const seg = cum[pi + 1] - cum[pi];
    const frac = seg > 0 ? (targetD - cum[pi]) / seg : 0;
    const eAtP = T[pi][2] + frac * ((T[pi + 1] || T[pi])[2] - T[pi][2]);
    const dotX = x(targetD / total), dotY = y(eAtP);

    const doneLine = T.slice(0, pi + 1).map((p, i) => `${i === 0 ? 'M' : 'L'}${x(cum[i] / total).toFixed(1)},${y(p[2]).toFixed(1)}`).join(' ') + ` L${dotX.toFixed(1)},${dotY.toFixed(1)}`;
    const doneArea = doneLine + ` L${dotX.toFixed(1)},${H - PAD} L${PAD},${H - PAD} Z`;

    svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
    svg.setAttribute('preserveAspectRatio', 'none');
    svg.innerHTML =
      `<path d="${fullArea}" fill="rgba(180,190,180,0.08)"/>` +
      `<path d="${full}" fill="none" stroke="rgba(180,190,180,0.3)" stroke-width="1"/>` +
      `<path d="${doneArea}" fill="rgba(46,180,95,0.25)"/>` +
      `<path d="${doneLine}" fill="none" stroke="rgba(86,220,135,0.85)" stroke-width="1.5"/>` +
      `<circle cx="${dotX}" cy="${dotY}" r="4" fill="rgb(86,220,135)"/>` +
      `<circle cx="${dotX}" cy="${dotY}" r="4" fill="none" stroke="#161b17" stroke-width="1.5"/>`;
  }
  window.drawElevSparkline = drawElevSparkline;

  // Render the phone chrome into the body — header, elev band, map-wrap with center buttons, footer.
